item.file:
"""Centralized Vikunja client with enforced project_id (Master Plan §D.1)."""
from __future__ import annotations
from typing import Any

class ProjectScopeError(ValueError):
    """Raised when a Vikunja query is attempted without explicit project_id."""

def _require_project_id(project_id: Any) -> int:
    # Note: bool is a subclass of int in Python, so we must explicitly reject it
    # to prevent `project_id=True` (which would resolve to project_id=1) from bypassing the gate.
    if project_id is None or isinstance(project_id, bool) or not isinstance(project_id, int):
        raise ProjectScopeError(
            "SECURITY: Vikunja queries require an explicit int project_id (not bool, not str, not None). "
            "'All tasks' queries are forbidden by Master Plan §D.1. "
            f"Got: {project_id!r}"
        )
    return project_id

class VikunjaClient:
    """Thin wrapper that enforces project scoping on list/search operations."""
    def __init__(self, base_url: str, token: str):
        self.base_url = base_url.rstrip("/")
        self.token = token

    def list_tasks(self, *, project_id: int, **filters):
        _require_project_id(project_id)
        # ... delegate to underlying HTTP client, passing project_id as filter ...

    def search_tasks(self, *, project_id: int, query: str, **filters):
        _require_project_id(project_id)
        # ... delegate ...

    def get_task(self, task_id: int):
        # Single-task get is permitted without project_id because it targets one record.
        ...

    # ... other methods: create_task, update_task, complete_task, etc.

item.test:
import pytest from tools._vikunja_client import VikunjaClient, ProjectScopeError
def test_list_without_project_id_raises(): c = VikunjaClient("http://localhost:3456", "x") with pytest.raises(ProjectScopeError): c.list_tasks(project_id=None)
def test_list_with_string_project_id_raises(): c = VikunjaClient("http://localhost:3456", "x") with pytest.raises(ProjectScopeError): c.list_tasks(project_id="1")
def test_list_with_bool_project_id_raises(): # bool is a subclass of int; the gate must reject it explicitly. c = VikunjaClient("http://localhost:3456", "x") with pytest.raises(ProjectScopeError): c.list_tasks(project_id=True) with pytest.raises(ProjectScopeError): c.list_tasks(project_id=False)
def test_list_with_int_project_id_ok(): c = VikunjaClient("http://localhost:3456", "x") # Should not raise — we don't need to assert on HTTP result here # (use mock or skip if no server running) pass

